cd /tmp && python3 - <<'EOF'
import json,re,glob,os,statistics as st,csv
lang={str(json.loads(l)['id']):json.loads(l)['language'] for l in open('/tmp/drb/data/prompt_data/query.jsonl')}
# map raw_data filename -> leaderboard model name
lb={}
for r in csv.DictReader(open('/home/polaris/polaris_project/drb_corpus/leaderboard_gemini25pro_judge.csv')):
    lb[r['model']]=float(r['insight'])
alias={'baidu-qianfan-drs-pro':'qianfan_deepresearch_0430','drb_cellcog_max':'cellcog-max','drb_cellcog':'drb_cellcog',
 'xiaoyi_research_agent_0304':'xiaoyi','tavily-research':'tavily-research','grep-v4':None,'baidu-qianfan-drs':None,
 'ms_deepresearch':'ms_deepresearch'}
out={}
for f in sorted(glob.glob('/tmp/drball/*.jsonl')):
    name=os.path.basename(f)[:-6]
    m=alias.get(name,name)
    if m is None or m not in lb: 
        if name in lb: m=name
        else: print("  [skip, no lb score]",name); continue
    rows=[json.loads(l) for l in open(f)]
    rows=[r for r in rows if lang.get(str(r['id']))=='en' and r.get('article')]
    n=len(rows)
    if n<40: print("  [skip, n=",n,"]",name); continue
    W=P=PL=B=H=TR=0
    for r in rows:
        a=r['article']
        if a.count('\n')==0 and '\\n' in a: a=a.replace('\\n','\n')
        lines=a.split('\n'); W+=len(a.split())
        paras=[p for p in re.split(r'\n\s*\n',a) if p.strip() and not p.strip().startswith(('#','|','-','*','>')) and not re.match(r'^\d+\.',p.strip())]
        P+=len(paras); PL+=sum(len(p.split()) for p in paras)
        B+=sum(1 for L in lines if re.match(r'^\s*([-*+]|\d+\.)\s',L))
        H+=sum(1 for L in lines if re.match(r'^#{3,}\s',L))
        TR+=sum(1 for L in lines if L.strip().startswith('|') and not re.match(r'^\|[\s:|-]+\|?$',L.strip()))
    out[m]=dict(ins=lb[m],words=W/n,paras=P/n,paraW=PL/max(P,1),bul=B/(W/1000),h3=H/n,tr=TR/n)
def pear(x,y):
    mx,my=st.mean(x),st.mean(y)
    return sum((a-mx)*(b-my) for a,b in zip(x,y))/((sum((a-mx)**2 for a in x)*sum((b-my)**2 for b in y))**.5)
keys=sorted(out,key=lambda k:-out[k]['ins']); y=[out[k]['ins'] for k in keys]
print("\nALL AVAILABLE SYSTEMS n=",len(keys))
for m,c in [('h3','+0.68'),('words','+0.59'),('tr','+0.58'),('paras','+0.47'),('bul','-0.05'),('paraW','-0.00')]:
    print(f"  r(insight,{m:6}) = {pear([out[k][m] for k in keys],y):+.3f}    [claim, n=11: {c}]")
print()
for k in keys: print(f"  {k:45} ins={out[k]['ins']:5.2f} h3={out[k]['h3']:6.1f} words={out[k]['words']:7.0f}")
EOF
